/**
 * Casa itens extraídos do PDF com o catálogo canônico e expande
 * a lista completa (qtd 0 onde não declarado).
 */
(function (global) {
  "use strict";

  function clean(s) {
    return String(s || "")
      .replace(/\u00a0/g, " ")
      .replace(/[‐‑‒–—―]/g, "-")
      .replace(/\s+/g, " ")
      .trim();
  }

  function norm(s) {
    return clean(s)
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();
  }

  function tokens(s) {
    return new Set(
      norm(s)
        .split(" ")
        .filter((t) => t.length > 2)
    );
  }

  function jaccard(a, b) {
    const A = tokens(a);
    const B = tokens(b);
    if (!A.size || !B.size) return 0;
    let inter = 0;
    A.forEach((t) => {
      if (B.has(t)) inter++;
    });
    return inter / (A.size + B.size - inter);
  }

  function startsScore(a, b) {
    const na = norm(a);
    const nb = norm(b);
    if (!na || !nb) return 0;
    const n = Math.min(50, na.length, nb.length);
    let same = 0;
    for (let i = 0; i < n; i++) {
      if (na[i] === nb[i]) same++;
      else break;
    }
    return same / n;
  }

  function includesScore(a, b) {
    const na = norm(a);
    const nb = norm(b);
    if (!na || !nb) return 0;
    if (na.includes(nb.slice(0, 60)) || nb.includes(na.slice(0, 60))) return 1;
    // first 8 significant words of shorter in longer
    const short = na.length <= nb.length ? na : nb;
    const long = na.length <= nb.length ? nb : na;
    const words = short.split(" ").slice(0, 10).join(" ");
    if (words.length > 20 && long.includes(words)) return 0.85;
    return 0;
  }

  /**
   * Score de similaridade item PDF × meta catálogo (0–100).
   */
  function scoreMatch(item, meta, id) {
    const desc = item.descricao || item.originalDescription || "";
    if (!desc || !meta) return 0;
    let s = 0;
    const jac = jaccard(desc, meta.description);
    const st = startsScore(desc, meta.description);
    const inc = includesScore(desc, meta.description);
    s += jac * 45;
    s += st * 25;
    s += inc * 20;

    const pu = Number(item.pontosUnitario);
    if (Number.isFinite(pu) && Math.abs(pu - meta.pointsPerUnit) < 0.05) s += 12;
    else if (Number.isFinite(pu) && Math.abs(pu - meta.pointsPerUnit) < 0.2) s += 4;

    const g = String(item.grupo || "").toUpperCase();
    if (g && g === meta.category) s += 6;

    // dicas titular/substituto (grupo V)
    const d = norm(desc);
    if (/\btitular\b/.test(d) && /\.t$/.test(id)) s += 8;
    if (/\bsubstitut/.test(d) && /\.s$/.test(id)) s += 8;
    if (/\bcd\s*0?2\b/.test(d) && /^V\.1/.test(id)) s += 5;
    if (/\bcd\s*0?[34]\b/.test(d) && /^V\.2/.test(id)) s += 5;
    if (/\bfg\s*0?[12]\b/.test(d) && /^V\.3/.test(id)) s += 5;
    if (/\bfg\s*0?[3-9]\b|a partir da fg/.test(d) && /^V\.4/.test(id)) s += 5;

    return s;
  }

  function matchCriterionId(item) {
    const ordem = global.RSC_CRITERIOS_ORDEM || [];
    const meta = global.RSC_CRITERIOS_META || {};
    let bestId = null;
    let best = 0;
    for (const id of ordem) {
      const sc = scoreMatch(item, meta[id], id);
      if (sc > best) {
        best = sc;
        bestId = id;
      }
    }
    // limiar: precisa de alguma semelhança real
    if (best < 28) return { id: null, score: best };
    return { id: bestId, score: best };
  }

  /**
   * Expande itens do PDF para a lista canônica completa.
   * @returns {{ itens: Array, unmatched: Array, matches: Array }}
   */
  function expandItensToCatalog(rawItens) {
    const ordem = global.RSC_CRITERIOS_ORDEM || [];
    const metaAll = global.RSC_CRITERIOS_META || {};
    const qtdById = new Map();
    const matches = [];
    const unmatched = [];

    /**
     * OCR de PDF escaneado costuma perder a vírgula decimal (7,5 → 75, 4,5 → 45).
     * Com o item casado no catálogo, recalcula qtd com pts/unid. oficiais.
     */
    function deriveQtdFromCatalog(it, catalogPu) {
      let pu = Number(it.pontosUnitario);
      let po = Number(it.pontosObtidos);
      if (!Number.isFinite(po) || po <= 0 || !catalogPu) {
        const q0 = Number(it.qtdDeclarada);
        return Number.isFinite(q0) && q0 > 0 ? q0 : 0;
      }
      // pts/unid. lidos 10× maiores que o catálogo (vírgula perdida)
      if (Number.isFinite(pu) && Math.abs(pu / 10 - catalogPu) < 0.08) {
        const qHi = po / catalogPu;
        const qLo = po / 10 / catalogPu;
        // ambos os números inflados: 75 75 → 1 unidade de 7,5
        if (
          qHi > 5 &&
          Math.abs(qLo - Math.round(qLo)) < 0.12 &&
          Math.abs(qHi - 10 * Math.round(qLo)) < 0.6
        ) {
          po = po / 10;
        }
        pu = catalogPu;
      } else {
        pu = catalogPu;
      }
      let qtd = po / pu;
      if (Math.abs(qtd - Math.round(qtd)) < 0.15) qtd = Math.round(qtd);
      else qtd = Math.round(qtd * 1000) / 1000;
      if (!Number.isFinite(qtd) || qtd < 0) qtd = 0;
      // se ainda absurdo (>40), tenta po/10
      if (qtd > 40 && Math.abs(po / 10 / pu - Math.round(po / 10 / pu)) < 0.12) {
        qtd = Math.round(po / 10 / pu);
      }
      return qtd;
    }

    (rawItens || []).forEach((it, idx) => {
      const { id, score } = matchCriterionId(it);
      if (!id) {
        unmatched.push({ index: idx, item: it, score });
        return;
      }
      const meta = metaAll[id];
      let qtd = deriveQtdFromCatalog(it, meta && meta.pointsPerUnit);
      if ((!qtd || qtd <= 0) && Number(it.qtdDeclarada) > 0) {
        qtd = Number(it.qtdDeclarada);
      }
      if (Math.abs(qtd - Math.round(qtd)) < 1e-6) qtd = Math.round(qtd);

      matches.push({ index: idx, criterionId: id, score, qtd });
      const prev = qtdById.get(id) || 0;
      qtdById.set(id, Math.round((prev + qtd) * 1000) / 1000);
    });

    const itens = ordem.map((id) => {
      const m = metaAll[id];
      const qtd = qtdById.has(id) ? qtdById.get(id) : 0;
      const pu = m.pointsPerUnit;
      const po = Math.round(qtd * pu * 10) / 10;
      // número do item no grupo (ex. I.3 → 3; V.1.t → 1)
      const numMatch = String(id).match(/^[IVX]+\.(\d+)/i);
      const n = numMatch ? Number(numMatch[1]) : null;
      return {
        criterionId: id,
        grupo: m.category,
        n,
        descricao: m.description,
        unidade: m.unit,
        pontosUnitario: pu,
        pontosObtidos: po,
        qtdDeclarada: qtd,
        qtdAceita: qtd,
        aceito: qtd > 0 ? "pend" : "no",
        obs: "",
        fromCatalog: true,
      };
    });

    return { itens, unmatched, matches, qtdById };
  }

  function catalogStats() {
    const ordem = global.RSC_CRITERIOS_ORDEM || [];
    return { total: ordem.length, groups: global.RSC_CATEGORIAS || {} };
  }

  global.RSCCriterios = {
    expandItensToCatalog,
    matchCriterionId,
    scoreMatch,
    catalogStats,
    getOrdem: () => global.RSC_CRITERIOS_ORDEM || [],
    getMeta: (id) => (global.RSC_CRITERIOS_META || {})[id] || null,
    getAllMeta: () => global.RSC_CRITERIOS_META || {},
    getCategorias: () => global.RSC_CATEGORIAS || {},
  };
})(typeof window !== "undefined" ? window : globalThis);
